import{_ as t,c as e,o as r,a2 as o}from"./chunks/framework.Sicmpk4x.js";const v=JSON.parse('{"title":"","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"book/overview.md","filePath":"book/overview.md"}'),a={name:"book/overview.md"},d=o('<blockquote> “What I cannot create, I do not understand.” — Richard Feynman </blockquote><p>This little book contains a series of course projects based on <a href="https://github.com/yhzhang0128/egos-2000" target="_blank"> egos-2000</a>. The goal is to help students gain experience and confidence in creating their own operating system or similar computer systems in their future career.</p><h3 id="core-projects" tabindex="-1">Core projects <a class="header-anchor" href="#core-projects" aria-label="Permalink to &quot;Core projects&quot;">​</a></h3><p>There are 6 <strong>core projects</strong> covering most of the OS concepts for an undergraduate-level OS course (e.g., CS4411 at Cornell). These core projects <em>introduce the architectural support for OS step-by-step</em>, which students at Cornell found very helpful. For example, students would implement a preemptive scheduler without any knowledge of privilege levels.</p><table tabindex="0"><thead><tr><th></th><th>OS concepts</th><th>Architectural support</th></tr></thead><tbody><tr><td>Hello, World!</td><td>code, data, heap, stack</td><td>user-level ISA</td></tr><tr><td>Multithreading 101</td><td>thread, context switch</td><td></td></tr><tr><td>Preemptive Scheduler</td><td>interrupt and exception handling</td><td>control register, timer interrupt</td></tr><tr><td>System Call</td><td>inter-process communication</td><td>privilege level</td></tr><tr><td>Virtual Memory</td><td>process address space</td><td>page table translation</td></tr><tr><td>File System</td><td>disk block, inode, file, directory</td><td></td></tr></tbody></table><h3 id="advanced-projects" tabindex="-1">Advanced projects <a class="header-anchor" href="#advanced-projects" aria-label="Permalink to &quot;Advanced projects&quot;">​</a></h3><p>There are 3 <strong>advanced projects</strong> for a master-level OS course (e.g., CS5411 at Cornell).</p><table tabindex="0"><thead><tr><th></th><th>OS concepts</th><th>Architectural support</th></tr></thead><tbody><tr><td>SD Card Driver</td><td>bus controller, device driver</td><td>memory-mapped I/O</td></tr><tr><td>Ethernet and UDP</td><td>TCP/IP four layers, I/O interrupt</td><td>platform-level interrupt controller</td></tr><tr><td>Multi-core and Lock</td><td>spinlock, bootstrap, critical section</td><td>atomic memory operation</td></tr></tbody></table><p>All the projects above can run on the QEMU emulator as well as actual RISC-V boards. Now, let&#39;s get hands dirty and have fun!</p>',9),n=[d];function s(c,i,l,p,h,u){return r(),e("div",null,n)}const b=t(a,[["render",s]]);export{v as __pageData,b as default};
